```cpp
// x64_codegen_engine.h - Drop-in replacement for broken code generator
#ifndef X64_CODEGEN_ENGINE_H
#define X64_CODEGEN_ENGINE_H

#include <cstdint>
#include <vector>
#include <string>
#include <unordered_map>
#include <variant>
#include <stdexcept>

namespace RawrXD {
namespace CodeGen {

// X64 Instruction Encoding Components
enum class Register : uint8_t {
    RAX = 0, RCX = 1, RDX = 2, RBX = 3,
    RSP = 4, RBP = 5, RSI = 6, RDI = 7,
    R8 = 8, R9 = 9, R10 = 10, R11 = 11,
    R12 = 12, R13 = 13, R14 = 14, R15 = 15,
    NONE = 0xFF
};

enum class OperandType {
    REG, MEM, IMM, LABEL_REF
};

struct Operand {
    OperandType type;
    Register reg;
    int32_t displacement;
    Register base;
    Register index;
    uint8_t scale;
    int64_t immediate;
    std::string label_name;
};

struct Instruction {
    std::string mnemonic;
    std::vector<Operand> operands;
    size_t line_number;
};

// PE Format Structures
struct PEHeader {
    uint16_t e_magic = 0x5A4D; // "MZ"
    uint16_t e_cblp = 0;
    uint16_t e_cp = 0;
    uint16_t e_crlc = 0;
    uint16_t e_cparhdr = 0;
    uint16_t e_minalloc = 0;
    uint16_t e_maxalloc = 0;
    uint16_t e_ss = 0;
    uint16_t e_sp = 0;
    uint16_t e_csum = 0;
    uint16_t e_ip = 0;
    uint16_t e_cs = 0;
    uint16_t e_lfarlc = 0;
    uint16_t e_ovno = 0;
    uint16_t e_res[4] = {0};
    uint16_t e_oemid = 0;
    uint16_t e_oeminfo = 0;
    uint16_t e_res2[10] = {0};
    uint32_t e_lfanew = 0x40;
    
    uint32_t pe_signature = 0x00004550; // "PE\0\0"
    uint16_t machine = 0x8664; // AMD64
    uint16_t number_of_sections = 2;
    uint32_t time_date_stamp = 0;
    uint32_t pointer_to_symbol_table = 0;
    uint32_t number_of_symbols = 0;
    uint16_t size_of_optional_header = 0xF0;
    uint16_t characteristics = 0x22; // EXECUTABLE_IMAGE | LARGE_ADDRESS_AWARE
    
    // Optional Header (PE32+)
    uint16_t magic = 0x20B; // PE32+
    uint8_t major_linker_version = 1;
    uint8_t minor_linker_version = 0;
    uint32_t size_of_code = 0;
    uint32_t size_of_initialized_data = 0;
    uint32_t size_of_uninitialized_data = 0;
    uint32_t entry_point = 0x1000;
    uint32_t base_of_code = 0x1000;
    uint64_t image_base = 0x0000000140000000;
    uint32_t section_alignment = 0x1000;
    uint32_t file_alignment = 0x200;
    uint16_t major_os_version = 6;
    uint16_t minor_os_version = 0;
    uint16_t major_image_version = 0;
    uint16_t minor_image_version = 0;
    uint16_t major_subsystem_version = 6;
    uint16_t minor_subsystem_version = 0;
    uint32_t win32_version_value = 0;
    uint32_t size_of_image = 0;
    uint32_t size_of_headers = 0x400;
    uint32_t check_sum = 0;
    uint16_t subsystem = 3; // Console
    uint16_t dll_characteristics = 0;
    uint64_t size_of_stack_reserve = 0x100000;
    uint64_t size_of_stack_commit = 0x1000;
    uint64_t size_of_heap_reserve = 0x100000;
    uint64_t size_of_heap_commit = 0x1000;
    uint32_t loader_flags = 0;
    uint32_t number_of_rva_and_sizes = 16;
    
    // Data Directories (simplified - just import table)
    uint64_t import_table_rva = 0;
    uint64_t import_table_size = 0;
    uint64_t iat_rva = 0;
    uint64_t iat_size = 0;
};

struct SectionHeader {
    char name[8] = {0};
    uint32_t virtual_size = 0;
    uint32_t virtual_address = 0;
    uint32_t size_of_raw_data = 0;
    uint32_t pointer_to_raw_data = 0;
    uint32_t pointer_to_relocations = 0;
    uint32_t pointer_to_linenumbers = 0;
    uint16_t number_of_relocations = 0;
    uint16_t number_of_linenumbers = 0;
    uint32_t characteristics = 0;
};

// Core Encoder
class X64Encoder {
private:
    std::vector<uint8_t> text_section;
    std::vector<uint8_t> data_section;
    std::unordered_map<std::string, size_t> labels;
    std::vector<std::pair<std::string, size_t>> label_refs;
    size_t current_rva = 0x1000;
    
    // REX prefix calculation
    bool needs_rex(const Operand& op) {
        if (op.type == OperandType::REG && static_cast<uint8_t>(op.reg) >= 8) return true;
        if (op.type == OperandType::MEM) {
            if (static_cast<uint8_t>(op.base) >= 8) return true;
            if (static_cast<uint8_t>(op.index) >= 8) return true;
        }
        return false;
    }
    
    uint8_t encode_rex(bool w, bool r, bool x, bool b) {
        return 0x40 | (w ? 0x08 : 0) | (r ? 0x04 : 0) | (x ? 0x02 : 0) | (b ? 0x01 : 0);
    }
    
    uint8_t encode_modrm(uint8_t mod, uint8_t reg, uint8_t rm) {
        return (mod << 6) | ((reg & 7) << 3) | (rm & 7);
    }
    
    uint8_t encode_sib(uint8_t scale, uint8_t index, uint8_t base) {
        return (scale << 6) | ((index & 7) << 3) | (base & 7);
    }
    
    void emit_bytes(const std::vector<uint8_t>& bytes) {
        text_section.insert(text_section.end(), bytes.begin(), bytes.end());
    }
    
    void emit_u32(uint32_t val) {
        text_section.push_back(val & 0xFF);
        text_section.push_back((val >> 8) & 0xFF);
        text_section.push_back((val >> 16) & 0xFF);
        text_section.push_back((val >> 24) & 0xFF);
    }
    
    void emit_u64(uint64_t val) {
        for (int i = 0; i < 8; i++) {
            text_section.push_back((val >> (i * 8)) & 0xFF);
        }
    }

public:
    void encode_mov_reg_imm64(Register reg, uint64_t imm) {
        // REX.W + B (if reg >= 8) + MOV r64, imm64 (0xB8+rd)
        bool needs_rex_b = static_cast<uint8_t>(reg) >= 8;
        emit_bytes({encode_rex(true, false, false, needs_rex_b)});
        emit_bytes({static_cast<uint8_t>(0xB8 + (static_cast<uint8_t>(reg) & 7))});
        emit_u64(imm);
    }
    
    void encode_mov_reg_imm32(Register reg, uint32_t imm) {
        // REX.W + MOV r/m64, imm32 (0xC7 /0 id) - zero extends
        bool needs_rex_b = static_cast<uint8_t>(reg) >= 8;
        emit_bytes({encode_rex(true, false, false, needs_rex_b)});
        emit_bytes({0xC7});
        emit_bytes({encode_modrm(3, 0, static_cast<uint8_t>(reg))});
        emit_u32(imm);
    }
    
    void encode_ret() {
        emit_bytes({0xC3});
    }
    
    void encode_push_reg(Register reg) {
        if (static_cast<uint8_t>(reg) >= 8) {
            emit_bytes({0x41, 0x50 + (static_cast<uint8_t>(reg) & 7)});
        } else {
            emit_bytes({0x50 + static_cast<uint8_t>(reg)});
        }
    }
    
    void encode_pop_reg(Register reg) {
        if (static_cast<uint8_t>(reg) >= 8) {
            emit_bytes({0x41, 0x58 + (static_cast<uint8_t>(reg) & 7)});
        } else {
            emit_bytes({0x58 + static_cast<uint8_t>(reg)});
        }
    }
    
    void encode_syscall() {
        emit_bytes({0x0F, 0x05});
    }
    
    void encode_call_relative(int32_t offset) {
        emit_bytes({0xE8});
        emit_u32(static_cast<uint32_t>(offset));
    }
    
    void define_label(const std::string& name) {
        labels[name] = text_section.size();
    }
    
    void reference_label(const std::string& name) {
        label_refs.push_back({name, text_section.size()});
        emit_u32(0); // Placeholder
    }
    
    void encode_instruction(const Instruction& inst) {
        // Simple instruction encoding dispatcher
        if (inst.mnemonic == "mov") {
            if (inst.operands.size() == 2 && 
                inst.operands[0].type == OperandType::REG &&
                inst.operands[1].type == OperandType::IMM) {
                
                if (inst.operands[1].immediate > 0xFFFFFFFF || inst.operands[1].immediate < 0) {
                    encode_mov_reg_imm64(inst.operands[0].reg, 
                                       static_cast<uint64_t>(inst.operands[1].immediate));
                } else {
                    encode_mov_reg_imm32(inst.operands[0].reg,
                                       static_cast<uint32_t>(inst.operands[1].immediate));
                }
            }
        } else if (inst.mnemonic == "ret") {
            encode_ret();
        } else if (inst.mnemonic == "push") {
            if (inst.operands[0].type == OperandType::REG) {
                encode_push_reg(inst.operands[0].reg);
            }
        } else if (inst.mnemonic == "pop") {
            if (inst.operands[0].type == OperandType::REG) {
                encode_pop_reg(inst.operands[0].reg);
            }
        } else if (inst.mnemonic == "syscall") {
            encode_syscall();
        } else if (inst.mnemonic == "call") {
            if (inst.operands[0].type == OperandType::LABEL_REF) {
                reference_label(inst.operands[0].label_name);
            }
        }
    }
    
    std::vector<uint8_t> generate_pe() {
        // Patch forward references
        for (auto& [label_name, offset] : label_refs) {
            if (labels.find(label_name) != labels.end()) {
                size_t target = labels[label_name];
                int32_t rel = static_cast<int32_t>(target - (offset + 4));
                // Patch at offset
                text_section[offset] = rel & 0xFF;
                text_section[offset+1] = (rel >> 8) & 0xFF;
                text_section[offset+2] = (rel >> 16) & 0xFF;
                text_section[offset+3] = (rel >> 24) & 0xFF;
            }
        }
        
        // Build PE
        std::vector<uint8_t> pe;
        PEHeader hdr;
        
        // Align sections
        while (text_section.size() % 0x200 != 0) text_section.push_back(0);
        while (data_section.size() % 0x200 != 0) data_section.push_back(0);
        
        hdr.size_of_code = static_cast<uint32_t>(text_section.size());
        hdr.size_of_initialized_data = static_cast<uint32_t>(data_section.size());
        hdr.size_of_image = 0x400 + text_section.size() + data_section.size() + 0x1000;
        
        // Write headers
        auto append = [&pe](const void* data, size_t size) {
            pe.insert(pe.end(), static_cast<const uint8_t*>(data), 
                     static_cast<const uint8_t*>(data) + size);
        };
        
        append(&hdr, sizeof(hdr));
        
        // Section headers
        SectionHeader text_hdr;
        strcpy_s(text_hdr.name, 8, ".text");
        text_hdr.virtual_size = static_cast<uint32_t>(text_section.size());
        text_hdr.virtual_address = 0x1000;
        text_hdr.size_of_raw_data = static_cast<uint32_t>(text_section.size());
        text_hdr.pointer_to_raw_data = 0x400;
        text_hdr.characteristics = 0x60000020; // CODE | EXECUTE | READ
        
        SectionHeader data_hdr;
        strcpy_s(data_hdr.name, 8, ".data");
        data_hdr.virtual_size = static_cast<uint32_t>(data_section.size());
        data_hdr.virtual_address = 0x1000 + text_section.size();
        data_hdr.size_of_raw_data = static_cast<uint32_t>(data_section.size());
        data_hdr.pointer_to_raw_data = 0x400 + text_section.size();
        data_hdr.characteristics = 0xC0000040; // INITIALIZED_DATA | READ | WRITE
        
        // Pad to section headers location
        while (pe.size() < 0x178) pe.push_back(0);
        
        append(&text_hdr, sizeof(text_hdr));
        append(&data_hdr, sizeof(data_hdr));
        
        // Pad to 0x400 (file alignment)
        while (pe.size() < 0x400) pe.push_back(0);
        
        // Append sections
        append(text_section.data(), text_section.size());
        if (!data_section.empty()) {
            append(data_section.data(), data_section.size());
        }
        
        return pe;
    }
    
    size_t get_code_offset() const { return text_section.size(); }
};

// AST Visitor for Code Generation
class CodeGenerator {
private:
    X64Encoder encoder;
    
    Register string_to_reg(const std::string& s) {
        static const std::unordered_map<std::string, Register> map = {
            {"rax", Register::RAX}, {"rcx", Register::RCX}, {"rdx", Register::RDX},
            {"rbx", Register::RBX}, {"rsp", Register::RSP}, {"rbp", Register::RBP},
            {"rsi", Register::RSI}, {"rdi", Register::RDI}, {"r8", Register::R8},
            {"r9", Register::R9}, {"r10", Register::R10}, {"r11", Register::R11},
            {"r12", Register::R12}, {"r13", Register::R13}, {"r14", Register::R14},
            {"r15", Register::R15}
        };
        auto it = map.find(s);
        return (it != map.end()) ? it->second : Register::NONE;
    }

public:
    void visit_program(const class ASTNode* node);
    void visit_instruction(const class ASTNode* node);
    void visit_label(const std::string& name) {
        encoder.define_label(name);
    }
    
    std::vector<uint8_t> compile(const std::vector<Instruction>& instructions) {
        for (const auto& inst : instructions) {
            encoder.encode_instruction(inst);
        }
        return encoder.generate_pe();
    }
    
    std::vector<uint8_t> finalize() {
        return encoder.generate_pe();
    }
};

} // namespace CodeGen
} // namespace RawrXD

#endif
